const substackRows = $('Get Substack Context').all();
const linkedinRows = $('Get LinkedIn Context').all();
const notionRows = $('Get Notion Context').all();

let text = '';

// 1. Substack
if (substackRows.length === 0 || !substackRows[0].json.post_title) {
  text += 'No recent Substack posts found.\n\n';
} else {
  text += '### RECENT SUBSTACK ARTICLES (Source Material) ###\n';
  substackRows.forEach((row, index) => {
    const p = row.json;
    text += `Title: ${p.post_title}\nURL: ${p.post_url}\nContent snippet: ${(p.post_content || '').substring(0, 2000)}\n\n`;
  });
}

// 2. LinkedIn
if (linkedinRows.length === 0 || !linkedinRows[0].json.post_content) {
  text += 'No past LinkedIn posts found.\n\n';
} else {
  text += '### PAST LINKEDIN POSTS (Use for style, formatting, and tone match) ###\n';
  linkedinRows.forEach((row, index) => {
    const p = row.json;
    text += `Post #${index + 1} (Published: ${p.published_at})\nContent: ${p.post_content}\n\n`;
  });
}

// 3. Notion
if (notionRows.length === 0 || !notionRows[0].json.page_title) {
  text += 'No recent Notion pages found.\n\n';
} else {
  text += '### NOTION BRAINSTORMING & NOTES (Additional Context) ###\n';
  notionRows.forEach((row, index) => {
    const p = row.json;
    text += `Title: ${p.page_title}\nContent: ${(p.page_content || '').substring(0, 1500)}\n\n`;
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/giusy.md', 'utf8');
} catch (e) {
  persona = 'Warm, brilliant AI Marketing Director named Giusy.';
}

return [{ json: { text, giusy_persona: persona } }];

const raw = $input.first().json.content || $input.first().json.response || '';
let jsonStr = raw.trim();

let linkedin_post = '';
let reasoning = '';
let parsed = false;

try {
  let cleanStr = jsonStr;
  const firstBrace = cleanStr.indexOf('{');
  const lastBrace = cleanStr.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    cleanStr = cleanStr.substring(firstBrace, lastBrace + 1);
  }
  cleanStr = cleanStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');
  const obj = JSON.parse(cleanStr);
  linkedin_post = obj.linkedin_post || '';
  reasoning = obj.brief_strategic_reasoning || '';
  parsed = true;
} catch (e) {
  // standard parsing failed
}

if (!parsed) {
  const postMatch = jsonStr.match(/"linkedin_post"\s*:\s*"([\s\S]*?)"\s*,\s*"brief_strategic_reasoning"/);
  if (postMatch) {
    linkedin_post = postMatch[1];
  } else {
    const altMatch = jsonStr.match(/"linkedin_post"\s*:\s*"([\s\S]*?)"\s*}/);
    if (altMatch) {
      linkedin_post = altMatch[1];
    } else {
      linkedin_post = raw.replace(/```json/g, '').replace(/```/g, '').trim();
    }
  }
  const reasonMatch = jsonStr.match(/"brief_strategic_reasoning"\s*:\s*"([\s\S]*?)"/);
  if (reasonMatch) {
    reasoning = reasonMatch[1];
  }

  linkedin_post = linkedin_post
    .replace(/\\n/g, '\n')
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, '\\');
  reasoning = reasoning
    .replace(/\\n/g, '\n')
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, '\\');
}

return [{ json: { linkedin_post, reasoning } }];

